operations.old:
if (current >= required) {
  ensureScannerAcknowledgement("This item is already fully scanned: " + resolvedSku, "warn");
  beep("error");
  skuScanInput.select();
  queueFocusActiveInput();
  return;
}

operations.new:
if (current >= required) {
  ensureScannerAcknowledgement("This item is already fully scanned, but it belongs to this pallet: " + resolvedSku, "warn");
  beep("success");
  skuScanInput.select();
  queueFocusActiveInput();
  return;
}
